    /// Server streaming: Stream all UploadSessions matching criteria
    type StreamListStream = ReceiverStream<Result<ProtoUploadSession, Status>>;

    async fn stream_list(
        &self,
        request: Request<StreamUploadSessionRequest>,
    ) -> Result<Response<Self::StreamListStream>, Status> {
        let req = request.into_inner();
        let (tx, rx) = mpsc::channel(128);
        let repository = self.repository.clone();
        
        tokio::spawn(async move {
            // Get items with streaming support
            let limit = if req.limit > 0 { req.limit as usize } else { usize::MAX };
            let sort_by = if req.sort_by.is_empty() { None } else { Some(req.sort_by.as_str()) };
            let sort_order = if req.sort_order.is_empty() { None } else { Some(req.sort_order.as_str()) };
            
            // Fetch items in batches
            let batch_size = 100;
            let mut page = 1;
            let mut sent = 0usize;
            
            loop {
                match repository.list(page, batch_size, sort_by, sort_order).await {
                    Ok((items, _total)) => {
                        if items.is_empty() {
                            break;
                        }
                        for item in items {
                            if sent >= limit {
                                return;
                            }
                            if tx.send(Ok(item.into())).await.is_err() {
                                return;
                            }
                            sent += 1;
                        }
                        page += 1;
                    }
                    Err(e) => {
                        let _ = tx.send(Err(Status::internal(e.to_string()))).await;
                        return;
                    }
                }
            }
        });
        
        Ok(Response::new(ReceiverStream::new(rx)))
    }

